import{A as e,E as t,O as n,S as r,b as i,f as a,g as o,h as s,i as c,n as l,u,x as d}from"./index-C6cID5ZY.js";var f={class:`content-main`},p={class:`content-wrapper`},m={class:`sidebar-container`},h={class:`sticky-toc`},g={class:`toc-list`},_=[`onClick`],v={class:`content-area`},y={class:`manual-container`},b={id:`faq`,class:`manual-section`},x={class:`faq-list`},S={class:`faq-question`},C={class:`faq-answer`},w=l({__name:`UserManualView`,setup(l){let w=c(),T=t(JSON.parse(localStorage.getItem(`user`)||`{}`)),E=t(`intro`),D=[{id:`intro`,label:`1. Introduction`},{id:`getting-started`,label:`2. Getting Started`},{id:`dashboard`,label:`3. Dashboard Overview`},{id:`submissions`,label:`4. Submitting Forms`},{id:`viewing`,label:`5. Viewing Submissions`},{id:`mandates`,label:`6. GAD Mandates Management`},{id:`budget`,label:`7. Budget Monitoring`},{id:`reports`,label:`8. Reports`},{id:`faq`,label:`9. Frequently Asked Questions`},{id:`support`,label:`10. Technical Support`}],O=[{q:`What should I do if I encounter an error while submitting a form?`,a:`Check that all required fields are filled out correctly. Ensure file sizes are within limits (10MB for activity designs, 15MB per file for reports). If the issue persists, contact technical support.`},{q:`Can I edit a submission after it has been submitted?`,a:`As a monitoring user, you cannot edit submissions. If changes are needed, please contact the GAD Office administrator.`},{q:`How do I view the full content of uploaded files?`,a:`Click the "Preview" button on any document to view it in the browser. Download buttons are not available for staff users.`},{q:`What does the "Archive" section contain?`,a:`The archive contains cancelled activity designs and completed activities (both designs and accomplishment reports). You can filter by status and type.`},{q:`How do I interpret the Activity Rating?`,a:`The activity rating uses a 0-100% scale with corresponding descriptors (Excellent, Very Satisfactory, Satisfactory, Needs Improvement, Unsatisfactory, Canceled). Refer to the rating table in the accomplishment report form.`}],k=e=>{E.value=e;let t=document.getElementById(e);if(t){let e=t.getBoundingClientRect().top+window.scrollY+-96;window.scrollTo({top:e,behavior:`smooth`})}};return i(()=>{(!T.value.id||![`Staff`,`gad_staff`].includes(T.value.role))&&w.push(`/login`)}),(t,i)=>(d(),s(u,null,[a(`main`,f,[a(`div`,p,[a(`div`,m,[a(`div`,h,[i[0]||=a(`h3`,{class:`toc-title`},` Table of Contents `,-1),a(`ul`,g,[(d(),s(u,null,r(D,t=>a(`li`,{key:t.id},[a(`button`,{onClick:e=>k(t.id),class:n([`sidebar-nav-item`,{"active-nav-item":E.value===t.id}])},e(t.label),11,_)])),64))])])]),a(`div`,v,[a(`div`,y,[i[2]||=o(`<div id="intro" class="manual-section" data-v-256b2e04><h1 class="page-title" data-v-256b2e04>User Manual</h1><p class="intro-text" data-v-256b2e04> Welcome to the Benguet State University Gender and Development Information Management System (GAD-IMS) User Manual. This guide will help you navigate and use the system effectively as a GAD Staff user. </p></div><div id="getting-started" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>2. Getting Started</h2><div class="subsection" data-v-256b2e04><div data-v-256b2e04><h3 class="subsection-title" data-v-256b2e04>2.1 Logging In</h3><p class="subsection-text" data-v-256b2e04> Access the system via your web browser using the provided URL. Enter your username and password credentials provided by the system administrator. </p></div><div data-v-256b2e04><h3 class="subsection-title" data-v-256b2e04>2.2 Navigating the Dashboard</h3><p class="subsection-text" data-v-256b2e04> After logging in, you will be directed to the Staff Dashboard. The left sidebar contains all main navigation menus including Dashboard, GAD Programs, Mandates Management, Budget Monitoring, and Reports. </p></div></div></div><div id="dashboard" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>3. Dashboard Overview</h2><p class="subsection-text" data-v-256b2e04> The dashboard provides a quick overview of key metrics and pending activities: </p><ul class="styled-list" data-v-256b2e04><li data-v-256b2e04><strong data-v-256b2e04>Pending Activities</strong> - Shows number of activity designs awaiting review</li><li data-v-256b2e04><strong data-v-256b2e04>Activity Designs</strong> - Count of submitted activity designs</li><li data-v-256b2e04><strong data-v-256b2e04>Accomplishment Reports</strong> - Count of submitted accomplishment reports</li><li data-v-256b2e04><strong data-v-256b2e04>GAD Budget</strong> - Displays current budget allocation and utilization</li><li data-v-256b2e04><strong data-v-256b2e04>Calendar Widget</strong> - Shows upcoming deadlines and scheduled activities</li><li data-v-256b2e04><strong data-v-256b2e04>Recent Activity Logs</strong> - Tracks recent system activities</li></ul></div><div id="submissions" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>4. Submitting Forms</h2><div class="subsection" data-v-256b2e04><h3 class="subsection-title" data-v-256b2e04>4.1 Activity Design Submission</h3><ol class="styled-list numeric" data-v-256b2e04><li data-v-256b2e04>Click the &quot;New Submission&quot; button on the sidebar or the floating action button</li><li data-v-256b2e04>Select &quot;Activity Design&quot; from the options</li><li data-v-256b2e04>Fill out the form with: <ul class="nested-list" data-v-256b2e04><li data-v-256b2e04>Nature of Transaction (Employee, INSET, Extension, or Student Activity)</li><li data-v-256b2e04>Activity Title</li><li data-v-256b2e04>Start and End Dates</li><li data-v-256b2e04>Start and End Times</li><li data-v-256b2e04>Venue</li><li data-v-256b2e04>Target Participants (max 6 digits)</li><li data-v-256b2e04>Proposed Budget</li><li data-v-256b2e04>Upload Activity Design file (PDF/DOCX)</li><li data-v-256b2e04>Proponent Information</li></ul></li><li data-v-256b2e04>Click &quot;Submit Activity Design&quot; to complete the submission</li></ol></div><div class="subsection" data-v-256b2e04><h3 class="subsection-title" data-v-256b2e04>4.2 Accomplishment Report Submission</h3><ol class="styled-list numeric" data-v-256b2e04><li data-v-256b2e04>Click the &quot;New Submission&quot; button on the sidebar or the floating action button</li><li data-v-256b2e04>Select &quot;Accomplishment Report&quot; from the options</li><li data-v-256b2e04>Fill out the form with: <ul class="nested-list" data-v-256b2e04><li data-v-256b2e04>Activity Title</li><li data-v-256b2e04>Control Number (select from approved activity designs dropdown)</li><li data-v-256b2e04>Start and End Dates</li><li data-v-256b2e04>Start and End Times</li><li data-v-256b2e04>Venue</li><li data-v-256b2e04>Number of Attendees (max 6 digits)</li><li data-v-256b2e04>Male/Female Participant Breakdown</li><li data-v-256b2e04>Activity Rating (0-100% with criteria table)</li><li data-v-256b2e04>Upload Report &amp; Attachments (multiple files accepted)</li><li data-v-256b2e04>Proponent Information</li></ul></li><li data-v-256b2e04>Click &quot;Submit Accomplishment Report&quot; to complete the submission</li></ol></div></div><div id="viewing" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>5. Viewing Submissions</h2><p class="subsection-text" data-v-256b2e04> As a GAD Staff user, you have monitoring access to view all submissions: </p><ul class="styled-list" data-v-256b2e04><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Activity Designs:</span> Navigate to &quot;Submitted Activity Designs&quot; from the sidebar to view all submitted designs. Click &quot;View&quot; on any row to see the complete details.</li><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Accomplishment Reports:</span> Navigate to &quot;Submitted Accomplishment Reports&quot; to view all reports. Click &quot;View&quot; to see the complete report with ratings and attachments.</li><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Filters:</span> Use the filter bar to sort by status, form type, office, or search by title/control number.</li></ul><div class="note-box" data-v-256b2e04> Note: Staff users can only view documents (preview only). No download buttons are available for uploaded files. </div></div><div id="mandates" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>6. GAD Mandates Management</h2><p class="subsection-text" data-v-256b2e04>This section displays all GAD mandates where the GAD Office is the responsible unit:</p><ul class="styled-list" data-v-256b2e04><li data-v-256b2e04>View the complete list of 22 GAD Office mandates</li><li data-v-256b2e04>Filter mandates by status (In Progress, Completed, Upcoming)</li><li data-v-256b2e04>Search for specific mandates by title</li><li data-v-256b2e04>Access the GAD Plan &amp; Budget document (PDF viewer)</li><li data-v-256b2e04>Assign mandates to accomplishment reports</li></ul></div><div id="budget" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>7. Budget Monitoring</h2><p class="subsection-text" data-v-256b2e04>The budget monitoring page provides:</p><ul class="styled-list" data-v-256b2e04><li data-v-256b2e04>Total GAD Budget overview</li><li data-v-256b2e04>GAD Office Budget breakdown by category</li><li data-v-256b2e04>Balance available for implementation</li><li data-v-256b2e04>Mandate-based budget utilization tracking with progress bars</li><li data-v-256b2e04>Recent budget utilization logs</li><li data-v-256b2e04>Expense category split summary</li></ul></div><div id="reports" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>8. Reports</h2><p class="subsection-text" data-v-256b2e04>Generate and view annual reports:</p><ul class="styled-list" data-v-256b2e04><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Annual Report:</span> Comprehensive report of GAD accomplishments with sex-disaggregated data</li><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>GAD Plan &amp; Budget:</span> View the GPB document in table or PDF format</li><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Export to Excel:</span> Download report data for offline analysis</li><li data-v-256b2e04><span class="bold-text" data-v-256b2e04>Year Selection:</span> Switch between different fiscal years (2024-2026)</li></ul></div>`,8),a(`div`,b,[i[1]||=a(`h2`,{class:`section-title`},`9. Frequently Asked Questions`,-1),a(`div`,x,[(d(),s(u,null,r(O,(t,n)=>a(`div`,{class:`faq-item`,key:n},[a(`h3`,S,`Q: `+e(t.q),1),a(`p`,C,`A: `+e(t.a),1)])),64))])]),i[3]||=o(`<div id="support" class="manual-section" data-v-256b2e04><h2 class="section-title" data-v-256b2e04>10. Technical Support</h2><p class="subsection-text" data-v-256b2e04>For technical assistance, bug reports, or system inquiries, please contact:</p><div class="support-box" data-v-256b2e04><p class="support-title" data-v-256b2e04>GAD-IMS System Administrator</p><p class="support-text" data-v-256b2e04>Gender and Development Office</p><p class="support-text" data-v-256b2e04>Benguet State University</p><p class="support-email" data-v-256b2e04>Email: gad.ims@bsu.edu.ph</p><p class="support-text" data-v-256b2e04>Tel: (074) 422-2401 loc 123</p></div><p class="version-info" data-v-256b2e04>System Version: 1.0 | Last Updated: January 2026</p></div>`,1)])])])]),i[4]||=a(`footer`,{class:`footer-watermark`},[a(`p`,{class:`watermark-text`},` Benguet State University - Gender and Development Information Management System | GAD-IMS v1.0 `)],-1)],64))}},[[`__scopeId`,`data-v-256b2e04`]]);export{w as default};